// Normalizes input from Fluent Forms or direct JSON webhook.
// Sets is_valid_input = true when content meets minimum quality requirements.

const raw  = $input.first().json;
const body = raw.body || raw;

let content, contentType, practiceArea, firmNameOverride;

if (body.form_id !== undefined && body.fields !== undefined) {
  // Fluent Forms webhook shape: { form_id, fields: { ... } }
  const f      = body.fields || {};
  content          = String(f.content || f.field_note || f.case_win || '');
  contentType      = String(f.content_type || 'field_note');
  practiceArea     = String(f.practice_area || '');
  firmNameOverride = String(f.firm_name || '');
} else {
  // Direct JSON webhook
  content          = String(body.content || body.field_note || body.case_win || '');
  contentType      = String(body.content_type || 'field_note');
  practiceArea     = String(body.practice_area || '');
  firmNameOverride = String(body.firm_name || '');
}

content = content.trim();

// Reject content that contains privileged or legal-advice language.
const LEGAL_PATTERN = /\b(attorney.client|work.product|privileged|legal.advice|legal.opinion|ABA|bar.complaint|you.should|we.advise|pursuant.to|under\s+[§\d])\b/i;
const containsLegal = LEGAL_PATTERN.test(content);

const isValidInput = content.length >= 20 && !containsLegal;

let validationNote = '';
if (!content)                 validationNote = 'No content submitted.';
else if (content.length < 20) validationNote = 'Content too short — minimum 20 characters.';
else if (containsLegal)       validationNote = 'Content appears to contain legal-advice or privileged language. Remove attorney-client references, legal opinions, or advice before submitting.';

return [{ json: {
  content,
  content_type:       contentType === 'case_win' ? 'case_win' : 'field_note',
  practice_area:      practiceArea,
  firm_name_override: firmNameOverride,
  is_valid_input:     isValidInput,
  validation_note:    validationNote,
  received_at:        new Date().toISOString(),
} }];

// Reads firm config from n8n Variables and constructs the Claude API request.
// Required variables: FIRM_NAME, FIRM_EMAIL, FIRM_FROM_EMAIL

const FIRM_NAME      = $vars.FIRM_NAME;
const FIRM_EMAIL     = $vars.FIRM_EMAIL;
const FIRM_FROM_EMAIL = $vars.FIRM_FROM_EMAIL;

if (!FIRM_NAME)       throw new Error('FIRM_NAME n8n Variable is not set. Go to Settings → Variables and add it.');
if (!FIRM_EMAIL)      throw new Error('FIRM_EMAIL n8n Variable is not set. Go to Settings → Variables and add it.');
if (!FIRM_FROM_EMAIL) throw new Error('FIRM_FROM_EMAIL n8n Variable is not set. Go to Settings → Variables and add it (can be the same as FIRM_EMAIL).');

const item         = $input.first().json;
const isWin        = item.content_type === 'case_win';
const contentLabel = isWin ? 'Case win' : 'Field note';
const practiceArea = item.practice_area || 'General practice';
const firmName     = item.firm_name_override || FIRM_NAME;

const prompt = `You are a marketing copywriter for ${firmName}, a law firm. Repurpose the ${contentLabel.toLowerCase()} below into four marketing assets.

Rules you must follow — no exceptions:
- Marketing copy only. No legal advice, legal opinions, case law citations, statutory references, or anything that constitutes legal counsel.
- No client names, case numbers, opposing party names, specific dollar amounts, or any detail that could identify a specific client or matter. Reference outcomes in general terms only (e.g. 'resolved favorably', 'secured a positive outcome', 'the client kept their business').
- For case wins, include 'Attorney Advertising. Past results do not guarantee future outcomes.' at the end of the linkedin_post and newsletter_blurb.
- Write for a non-lawyer audience. Plain language. Warm, professional, human.

Practice area: ${practiceArea}
Content type: ${contentLabel}

Content:
${item.content}

Return ONLY a valid JSON object — no markdown fences, no preamble, no explanation outside the JSON. Keys required:
- linkedin_post: max 1,300 characters; professional, warm, shows the human side of practice; call to action to contact the firm at the end; Attorney Advertising footer if case win
- newsletter_blurb: max 200 words; conversational, trust-building, references the outcome type without identifying details; Attorney Advertising footer if case win
- gbp_post: max 1,500 characters; what the firm does for clients, locally relevant, positive, encourages contact
- faq_entry: a question a prospective client would search for on the first line (starting with 'Q:'), then a plain-language answer about the firm's process or values on the second line (starting with 'A:') — no legal advice in the answer
- is_marketing_safe: true

If producing safe copy is impossible without legal advice or identifying details, return only: {"is_marketing_safe": false, "safety_note": "brief reason"}`;

return [{ json: {
  ...item,
  firm_name:       firmName,
  firm_email:      FIRM_EMAIL,
  firm_from_email: FIRM_FROM_EMAIL,
  claude_request:  {
    model:      'claude-sonnet-4-6',
    max_tokens: 2048,
    messages:   [{ role: 'user', content: prompt }],
  },
} }];

// Parses Claude's JSON response and runs a post-hoc keyword safety scan on all four outputs.
// is_marketing_safe is true only if both Claude AND the scan pass.
// References 'Build Content Prompt' for firm config and content metadata.

const prepareData  = $('Build Content Prompt').item.json;
const practiceArea = prepareData.practice_area || 'General practice';
const firmName     = prepareData.firm_name     || 'Your Law Firm';
const contentType  = prepareData.content_type  || 'field_note';

// Claude API response shape: { content: [{ type: 'text', text: '...' }], ... }
const rawResponse = $input.first().json;
const rawText = (rawResponse.content && rawResponse.content[0] && rawResponse.content[0].text)
  ? rawResponse.content[0].text.trim()
  : '';

if (!rawText) {
  throw new Error('Claude API returned an empty response. Check the Anthropic API key, usage quota, and rate limits at console.anthropic.com.');
}

let parsed;
try {
  // Strip markdown fences if Claude added them despite instructions
  const cleaned = rawText.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude did not return valid JSON. Raw response: ' + rawText.slice(0, 400));
}

// If Claude self-flagged the content as unsafe, return early with a human-review package
if (parsed.is_marketing_safe === false) {
  return [{ json: {
    is_marketing_safe: false,
    safety_note:       parsed.safety_note || 'Claude flagged this content as unsafe to repurpose.',
    linkedin_post:     '',
    newsletter_blurb:  '',
    gbp_post:          '',
    faq_entry:         '',
    email_subject:     'Content Repurposer — flagged for human review — ' + practiceArea,
    email_body:        'The Content Repurposer flagged the submitted ' + (contentType === 'case_win' ? 'case win' : 'field note') + ' as unsafe to repurpose.\n\nReason: ' + (parsed.safety_note || 'None provided') + '\n\nOriginal content submitted:\n' + prepareData.content,
    practice_area:     practiceArea,
    content_type:      contentType,
    received_at:       prepareData.received_at || new Date().toISOString(),
  } }];
}

const outputs = {
  linkedin_post:    String(parsed.linkedin_post    || ''),
  newsletter_blurb: String(parsed.newsletter_blurb || ''),
  gbp_post:         String(parsed.gbp_post         || ''),
  faq_entry:        String(parsed.faq_entry         || ''),
};

// Post-hoc keyword scan — catches legal language that slipped past Claude's self-check
const UNSAFE_RE = /\b(attorney.client|work.product|privileged|legal.advice|legal.opinion|you should|we advise|we recommend|our recommendation|pursuant to|under\s+[§\d]|case law|statute|court held|court ruled|court\s+held|ruling)\b/i;

const scanFlags = {};
let anyFlagged = false;
for (const [key, text] of Object.entries(outputs)) {
  const flagged = UNSAFE_RE.test(text);
  scanFlags[key] = flagged ? 'REVIEW FIRST' : 'READY TO PUBLISH';
  if (flagged) anyFlagged = true;
}

const isSafe = !anyFlagged;

// Character and word counts for the email summary
const counts = {
  linkedin_post:    { chars: outputs.linkedin_post.length,    words: outputs.linkedin_post.trim().split(/\s+/).filter(Boolean).length },
  newsletter_blurb: { chars: outputs.newsletter_blurb.length, words: outputs.newsletter_blurb.trim().split(/\s+/).filter(Boolean).length },
  gbp_post:         { chars: outputs.gbp_post.length,         words: outputs.gbp_post.trim().split(/\s+/).filter(Boolean).length },
  faq_entry:        { chars: outputs.faq_entry.length,        words: outputs.faq_entry.trim().split(/\s+/).filter(Boolean).length },
};

const isWin      = contentType === 'case_win';
const typeLabel  = isWin ? 'Case win' : 'Field note';
const consentWarn = isWin
  ? '\n⚠  CASE WIN — Confirm written client consent is on file before publishing any of these assets.\n'
  : '';
const DIV = '─'.repeat(60);

const emailSubject = 'Content package ready — ' + practiceArea + ' ' + typeLabel.toLowerCase() + ' — ' + new Date().toLocaleDateString('en-US');

const emailBody = [
  'Content Package — ' + firmName,
  'Type: ' + typeLabel + '  |  Practice area: ' + practiceArea,
  consentWarn,
  '',
  DIV,
  'LINKEDIN POST  (' + counts.linkedin_post.chars + ' / 1,300 chars) — ' + scanFlags.linkedin_post,
  DIV,
  outputs.linkedin_post,
  '',
  DIV,
  'NEWSLETTER BLURB  (' + counts.newsletter_blurb.words + ' words) — ' + scanFlags.newsletter_blurb,
  DIV,
  outputs.newsletter_blurb,
  '',
  DIV,
  'GOOGLE BUSINESS PROFILE POST  (' + counts.gbp_post.chars + ' / 1,500 chars) — ' + scanFlags.gbp_post,
  DIV,
  outputs.gbp_post,
  '',
  DIV,
  'FAQ ENTRY  (' + counts.faq_entry.words + ' words) — ' + scanFlags.faq_entry,
  DIV,
  outputs.faq_entry,
  '',
  DIV,
  'BEFORE PUBLISHING',
  '• "REVIEW FIRST" assets need a human check — the safety scan found legal-sounding language',
  '• All case-win assets must include "Attorney Advertising. Past results do not guarantee future outcomes."',
  '• Google Business Profile rejects posts over 1,500 characters',
  '• Newsletter: confirm your email platform\'s unsubscribe footer is active for every send',
  'Generated: ' + new Date().toISOString(),
].join('\n');

return [{ json: {
  is_marketing_safe: isSafe,
  scan_flags:        scanFlags,
  counts,
  email_subject:     emailSubject,
  email_body:        emailBody,
  practice_area:     practiceArea,
  content_type:      contentType,
  received_at:       prepareData.received_at || new Date().toISOString(),
  ...outputs,
} }];
